function subscribe(e) {
    var params = new URLSearchParams(e);
    var nome = params.get("name") || "Lead sem nome";
    var email = params.get("emailAddress") || "";
    var telefone = params.get("phone") || "";
    var cpf = params.get("cpf") || "";
    var dataNascimento = params.get("birthdate") || ""; // Puxa a data do formulário
    var sourceId = params.get("sourceId") || "";
  
    // 1. Ajuste FormSubmit
    var payloadFormSubmit = e + "&_captcha=false&email=" + encodeURIComponent(email);
    
    // Suas URLs
    var urlFluentCRM = "https://sis.jotacorretor.com/?fluentcrm=1&route=contact&hash=3b3675cb-2e4e-48af-b726-de9a910e3f0d";
    var urlFluentBoards = "https://sis.jotacorretor.com/?fbs=1&route=task&hash=708425eb-5b23-4206-a499-f88339015e15";
  
    try {
      // 2. Disparo FluentCRM: Dados separados para mapeamento fácil no painel
      var fluentCrmData = new URLSearchParams();
      fluentCrmData.append("first_name", nome.split(" ")[0]);
      fluentCrmData.append("last_name", nome.split(" ").slice(1).join(" "));
      fluentCrmData.append("email", email);
      fluentCrmData.append("phone", telefone);
      fluentCrmData.append("cpf", cpf);
      fluentCrmData.append("date_of_birth", dataNascimento); // Envia para o CRM
      fluentCrmData.append("source", sourceId);


      fetch(urlFluentCRM, {
        method: "POST",
        headers: { "Content-Type": "application/x-www-form-urlencoded;charset=UTF-8" },
        body: fluentCrmData.toString()
      }).catch(function(err){ console.error("Erro FluentCRM:", err); });
  
  
      // 3. Disparo Fluent Boards
      var fluentBoardsData = new URLSearchParams();
      fluentBoardsData.append("title", "Novo Lead: " + nome);
      fluentBoardsData.append("contact_email", email);
      fluentBoardsData.append("contact_first_name", nome.split(" ")[0]);
      fluentBoardsData.append("contact_last_name", nome.split(" ").slice(1).join(" "));
      fluentBoardsData.append("description", "Email: " + email + "\nTelefone: " + telefone + "\nCPF: " + cpf + "\nOrigem: " + sourceId);
  
      fetch(urlFluentBoards, {
        method: "POST",
        headers: { "Content-Type": "application/x-www-form-urlencoded;charset=UTF-8" },
        body: fluentBoardsData.toString()
      }).catch(function(err){ console.error("Erro FluentBoards:", err); });
  
    } catch(err) {
      console.error("Erro ao preparar webhooks:", err);
    }
  
    // 4. Disparo Final FormSubmit
    return SUBSCRIBE_URL
      ? fetch(SUBSCRIBE_URL, {
          method: "POST",
          headers: {
            "Content-Type": "application/x-www-form-urlencoded;charset=UTF-8",
            "Accept": "application/json"
          },
          body: payloadFormSubmit
        })
      : Promise.reject(
          new Error("[form] apiSubscribe ausente em LP_CONFIG.brand.")
        );
  }




